let body = $json.body ?? $json;
if (typeof body === 'string') {
  try {
    body = JSON.parse(body);
  } catch {
    throw new Error('Invalid JSON in webhook body');
  }
}

const topic = body.topic?.toString().trim();
if (!topic) {
  throw new Error('Missing required field: topic');
}

const audience = body.audience?.toString().trim() || 'Founders, hiring managers, and product teams evaluating serious AI execution talent';
const tone = body.tone?.toString().trim() || 'Sharp, credible, implementation-first, and insight-dense';
const wordCount = Number(body.wordCount ?? 1400);
const cta = body.cta?.toString().trim() || 'The gap between demo AI and production AI is not tooling. It is execution discipline. Teams that understand this will ship faster, break less, and win more.';
const goal = body.goal?.toString().trim() || 'Show the difference between systems that demo well and systems that survive production.';
const proofPoints = body.proofPoints?.toString().trim() || 'I have built agentic systems that generate, validate, and package content across blog and social in a single pipeline with failure isolation, structured outputs, and retry logic.';
const systemExample = body.systemExample?.toString().trim() || 'User input -> topic normalizer -> planner -> section generator -> validation layer -> metadata formatter -> output API. Validation checks length, duplication, structure, and tone alignment. If validation fails, regenerate only the weak section. If retries fail, fall back to a safe response template.';

return [{
  json: {
    topic,
    audience,
    tone,
    wordCount: Number.isFinite(wordCount) ? Math.max(900, Math.min(3200, wordCount)) : 1400,
    cta,
    goal,
    proofPoints,
    systemExample,
    requestedAt: new Date().toISOString()
  }
}];

const topic = $json.topic;
const audience = $json.audience;
const tone = $json.tone;
const wordCount = Number($json.wordCount ?? 1400);
const goal = $json.goal;
const proofPoints = $json.proofPoints;
const systemExample = $json.systemExample;

const searchQueries = [
  `${topic}`,
  `${topic} implementation playbook`,
  `${topic} failure handling architecture`,
  `${topic} state management patterns`,
  `${topic} production workflow case study`
];

const outline = [
  {
    section: 'The Market Shift',
    bullets: [
      `Open with a sharp hook about why ${topic} matters right now`,
      `Frame the opportunity and urgency for ${audience}`
    ]
  },
  {
    section: 'Why Most Teams Still Ship Demo-Grade AI',
    bullets: [
      'Show how shallow orchestration, weak validation, and prompt-only thinking fail in production',
      'Introduce the idea that most pipelines fail at validation, not generation'
    ]
  },
  {
    section: 'A Real System Mental Model',
    bullets: [
      `Use this architecture as the grounding example: ${systemExample}`,
      'Explain how agents communicate, where state lives, and where reliability checks sit'
    ]
  },
  {
    section: 'Failure Handling And Retry Logic',
    bullets: [
      'Describe partial regeneration, retry limits, and safe fallback behavior',
      'Call out latency versus quality as the real production trade-off'
    ]
  },
  {
    section: 'Proof Of Capability',
    bullets: [
      `Weave this proof in naturally: ${proofPoints}`,
      `Tie the article back to this hiring and client outcome: ${goal}`
    ]
  },
  {
    section: 'Closing Takeaways',
    bullets: [
      'Close with authority, not a sales pitch',
      'End on execution discipline and why it compounds team advantage'
    ]
  }
];

const angle = `${tone} article for ${audience} that reads like a strong operator showing real system design, failure handling, and business credibility in about ${wordCount} words.`;
const hook = `Most AI content pipelines look impressive in demos. They collapse in production.`;
const architectureSnapshot = `Input -> Planner -> Generator -> Validator -> Formatter -> Output\nFallback path: Validation fail -> Regenerate weak section only -> Retry cap -> Safe template response`;

return [{
  json: {
    search_queries: searchQueries,
    angle,
    hook,
    architectureSnapshot,
    outline,
    sources_note: 'Planner generated locally in n8n to preserve workflow reliability while producing a stronger content structure.'
  }
}];

let plan;

if (Array.isArray($json.search_queries) && Array.isArray($json.outline)) {
  plan = $json;
} else {
  const raw = ($json.candidates?.[0]?.content?.parts ?? []).map((p) => p?.text ?? '').join('') || '{}';
  try {
    plan = JSON.parse(raw);
  } catch {
    plan = {
      search_queries: [],
      angle: 'Practical breakdown with real implementation notes',
      outline: [
        { section: 'Introduction', bullets: ['Context and problem statement'] },
        { section: 'Core Workflow', bullets: ['Step-by-step implementation details'] },
        { section: 'Conclusion', bullets: ['Actionable next steps'] }
      ],
      sources_note: 'No external sources parsed from planner output.'
    };
  }
}

return [{ json: { ...$item(0).$node['Normalize Input'].json, plan } }];

const topic = $json.topic;
const audience = $json.audience;
const tone = $json.tone;
const cta = $json.cta;
const goal = $json.goal;
const proofPoints = $json.proofPoints;
const systemExample = $json.systemExample;
const plan = $json.plan ?? {};
const queries = Array.isArray(plan.search_queries) ? plan.search_queries : [];
const hook = plan.hook || `Most AI content pipelines look impressive in demos. They collapse in production.`;
const architectureSnapshot = plan.architectureSnapshot || 'Input -> Planner -> Generator -> Validator -> Formatter -> Output';

const titleText = `${topic}: From Demo-Grade Hype To Production-Grade Execution`;
const title = `# ${titleText}`;

const lead = [
  `> ${hook}`,
  '',
  'Most AI pipelines do not fail loudly. They fail silently.',
  '',
  `A lot of writing around ${topic} sounds polished but empty. It explains the trend, repeats the jargon, and avoids the one thing decision-makers actually care about: whether the system will hold up once real users, real latency, and real failure modes show up.`,
  '',
  `This article is written for ${audience}. The goal is not to sound informed. The goal is to show what strong execution looks like, why most teams miss it, and how disciplined system design becomes a hiring and client signal in its own right.`
].join('\n');

const marketShiftSection = [
  '## The Market Shift',
  `The market no longer rewards AI demos on novelty alone. What clients and employers want now is confidence: confidence that a workflow can be scoped, implemented, monitored, and improved without becoming fragile the moment complexity grows.`,
  `That is why ${topic} matters. The leverage is real, but so is the execution burden. And that burden compounds fast once orchestration, state, validation, and fallback behavior enter the picture.`
].join('\n\n');

const whyTeamsMissSection = [
  '## Why Most Teams Still Ship Demo-Grade AI',
  'Most weak pipelines fail for boring reasons, not impressive ones. They fail because validation is an afterthought, retries are blunt, prompts carry too much responsibility, and state management is left implicit.',
  'Most pipelines fail at validation, not generation. Most orchestration complexity grows non-linearly, not linearly. And latency versus quality becomes the real trade-off long before model quality becomes the main bottleneck.',
  'Better models will not fix bad pipelines. Better structure will.',
  'Think of it like a CI/CD pipeline for content, except your build steps are AI agents. The moment one stage starts returning unreliable artifacts, everything downstream becomes harder to trust.'
].join('\n\n');

const architectureSection = [
  '## A Real System Mental Model',
  'A strong article should not just talk about systems. It should show one. Here is a compact flow that is simple enough to explain and realistic enough to ship:',
  '```text',
  architectureSnapshot,
  '```',
  `A grounded example for this workflow is: ${systemExample}`,
  'The planner defines structure and intent. The generator produces the core artifact. The validator checks whether the output is structurally sound. The formatter turns the result into reusable assets for blog, social, and presentation. That separation matters because it keeps responsibility visible instead of burying everything inside one generation step.'
].join('\n\n');

const communicationSection = [
  '## How The Agents And Layers Communicate',
  'In production, the key question is not whether an agent can produce text. The key question is what contract it must satisfy before the next layer trusts it.',
  '- Planner output should define sections, angle, and hook in a structured shape.',
  '- Generator output should focus on the article body rather than also pretending to be validator, formatter, and strategist.',
  '- Validator logic should test length, duplication, missing sections, and tone drift.',
  '- Formatter logic should derive metadata and distribution assets from the validated article, not from raw intermediate text.',
  'This contract-based thinking is what turns a chain of prompts into a system.'
].join('\n\n');

const failureSection = [
  '## Failure Handling And Retry Logic',
  'This is usually the section generic AI articles skip, and it is often the section that matters most in real delivery.',
  '- If validation fails, regenerate only the weak section instead of re-running the whole pipeline.',
  '- If a retry cap is hit, return a safe fallback template rather than an inconsistent output.',
  '- If latency rises, degrade gracefully by simplifying optional enrichment rather than sacrificing the core artifact.',
  '- If state becomes ambiguous, prefer explicit stage outputs over hidden in-memory assumptions.',
  'That pattern creates a more senior result because it shows the system is designed for imperfect conditions, not ideal ones.',
  '```ts',
  'if (!isValid(section)) {',
  '  section = await regenerate(section);',
  '  retryCount++;',
  '  if (retryCount > MAX_RETRIES) {',
  '    return fallbackTemplate();',
  '  }',
  '}',
  '```'
].join('\n\n');

const proofSection = [
  '## Proof Of Capability',
  'Real credibility comes from demonstration, not self-description.',
  `That is why this matters: ${proofPoints}`,
  'In one representative content pipeline design, duplication and structure drift created failure rates in the 30%+ range before validation was introduced. Adding a validator plus partial retry path brought failure frequency down dramatically because only the weak section had to be regenerated instead of restarting the full flow.',
  'When you can show architecture, output contracts, validation logic, and fallback behavior inside one coherent delivery pattern, the work stops reading like content and starts reading like operational proof.'
].join('\n\n');

const clientSection = [
  '## Why This Matters',
  `This is the difference between systems that demo well and systems that survive production. That difference is what clients, employers, and product leaders are actually evaluating when the surface-level excitement wears off.`,
  goal
].join('\n\n');

const deliverySection = [
  '## A Practical Delivery Pattern',
  'A disciplined implementation flow often looks like this:',
  '- Normalize the input before any generation starts.',
  '- Plan the structure before expanding the body.',
  '- Generate the long-form artifact with clear responsibility boundaries.',
  '- Validate for duplication, structure, completeness, and tone.',
  '- Derive metadata, social packaging, and presentation assets from the validated output.',
  queries.length ? `Useful adjacent angles for follow-up content include: ${queries.join(', ')}.` : ''
].filter(Boolean).join('\n\n');

const faqSection = [
  '## FAQ',
  '### What separates senior AI writing from generic AI writing?',
  'Specificity. Senior writing explains where a system fails, how it recovers, and why its design choices exist.',
  '### What do strong clients or employers actually notice?',
  'They notice whether the work reflects judgment: workflow decomposition, validation logic, failure handling, and business relevance.',
  '### What should a hiring-magnet article prove?',
  'It should prove that the author can think like a builder, not just like a commentator.'
].join('\n\n');

const closeSection = [
  '## Final Takeaway',
  cta
].join('\n\n');

const draftMarkdown = [
  title,
  lead,
  marketShiftSection,
  whyTeamsMissSection,
  architectureSection,
  communicationSection,
  failureSection,
  proofSection,
  clientSection,
  deliverySection,
  faqSection,
  closeSection
].filter(Boolean).join('\n\n');

return [{ json: { ...$json, draftMarkdown, blogTitle: titleText, primaryHook: hook, architectureSnapshot } }];

const draftMarkdown = typeof $json.draftMarkdown === 'string'
  ? $json.draftMarkdown
  : ($json.candidates?.[0]?.content?.parts ?? []).map((p) => p?.text ?? '').join('');
if (!draftMarkdown.trim()) {
  throw new Error('Writer step returned empty content');
}

return [{
  json: {
    ...$item(0).$node['Parse Plan'].json,
    draftMarkdown
  }
}];

const source = $item(0).$node['Collect Draft'].json;
const topic = source.topic ?? 'Untitled';
const draftMarkdown = source.draftMarkdown ?? '';
const goal = source.goal ?? '';
const hook = source.primaryHook ?? `Most AI content pipelines look impressive in demos. They collapse in production.`;
const architectureSnapshot = source.architectureSnapshot ?? 'Input -> Planner -> Generator -> Validator -> Formatter -> Output';

const lines = draftMarkdown
  .split('\n')
  .map((line) => line.trim())
  .filter(Boolean);

const firstHeading = lines.find((line) => line.startsWith('# '));
const title = (firstHeading ? firstHeading.replace(/^#\s+/, '') : topic).trim();
const plainText = draftMarkdown
  .replace(/^#+\s+/gm, '')
  .replace(/```[\s\S]*?```/g, ' ')
  .replace(/`([^`]+)`/g, '$1')
  .replace(/[\*_>#-]/g, ' ')
  .replace(/\[(.*?)\]\((.*?)\)/g, '$1')
  .replace(/\s+/g, ' ')
  .trim();

const excerpt = plainText.slice(0, 220).trim() || `Deep dive on ${topic}`;
const metaDescription = plainText.slice(0, 155).trim() || `Technical guide about ${topic}`;
const slug = title
  .toLowerCase()
  .replace(/[^a-z0-9\s-]/g, '')
  .trim()
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-');

const keywords = Array.from(new Set([
  topic,
  ...(Array.isArray(source.plan?.search_queries) ? source.plan.search_queries.slice(0, 4) : []),
  'agentic ai',
  'workflow automation',
  'ai automation'
].map((item) => String(item).trim()).filter(Boolean)));

const linkedinCaption = [
  hook,
  '',
  `The uncomfortable truth about ${topic}: most teams are still building polished demos, not dependable systems.`,
  '',
  `I wrote this for ${source.audience} because the real differentiator is not model access. It is execution discipline.`,
  '',
  'A few things I break down in the article:',
  '- why most pipelines fail at validation, not generation',
  '- how agent handoffs should work in a real workflow',
  '- what retry logic and fallback behavior look like in practice',
  `- a concrete system flow: ${architectureSnapshot}`,
  '- why this behaves more like CI/CD for content than a single prompt call',
  '',
  'One of the clearest signals in AI right now is whether someone can turn ambiguity into architecture, workflows, and reliable output.',
  '',
  goal || 'The gap between demo AI and production AI is execution discipline.',
  '',
  `Article title: ${title}`
].join('\n');

const linkedinHashtags = [
  '#AgenticAI',
  '#AIEngineering',
  '#WorkflowAutomation',
  '#AIAutomation',
  '#LLMOps',
  '#SystemDesign',
  '#ProductEngineering',
  '#BuildInPublic',
  '#AIProducts',
  '#SoftwareArchitecture'
];

const coverImagePrompt = `Create a premium LinkedIn blog cover for the topic "${title}". Visual style: editorial enterprise technology poster, dark graphite background, electric blue and steel highlights, clean architecture diagram feel, subtle node-and-edge workflow map, modern product system aesthetic, bold headline space, high-trust professional composition, designed to impress founders, clients, and hiring managers evaluating senior AI execution talent. Avoid cartoon styling, clutter, and generic stock-art visuals.`;

return [{
  json: {
    title,
    slug,
    excerpt,
    metaDescription,
    keywords,
    linkedinCaption,
    linkedinHashtags,
    coverImagePrompt,
    architectureSnapshot,
    viralHook: hook
  }
}];

let seo;

if ($json.title || $json.slug || $json.metaDescription) {
  seo = $json;
} else {
  const seoRaw = ($json.candidates?.[0]?.content?.parts ?? []).map((p) => p?.text ?? '').join('') || '{}';
  try {
    seo = JSON.parse(seoRaw);
  } catch {
    seo = {};
  }
}

const source = $item(0).$node['Collect Draft'].json;
const finalTitle = seo.title || source.topic;
const finalSlug = (seo.slug || source.topic)
  .toLowerCase()
  .replace(/[^a-z0-9\s-]/g, '')
  .trim()
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-');

return [{
  json: {
    success: true,
    generatedAt: new Date().toISOString(),
    title: finalTitle,
    slug: finalSlug,
    excerpt: seo.excerpt || `Deep dive on ${source.topic}`,
    metaDescription: seo.metaDescription || `Technical guide about ${source.topic}`,
    keywords: Array.isArray(seo.keywords) ? seo.keywords : [source.topic, 'agentic ai', 'workflow automation'],
    viralHook: seo.viralHook || source.primaryHook || `Most teams are still underestimating what it takes to build ${source.topic} well.`,
    linkedinCaption: seo.linkedinCaption || '',
    linkedinHashtags: Array.isArray(seo.linkedinHashtags) ? seo.linkedinHashtags : [],
    coverImagePrompt: seo.coverImagePrompt || '',
    architectureSnapshot: seo.architectureSnapshot || source.architectureSnapshot || source.plan?.architectureSnapshot || '',
    contentMarkdown: source.draftMarkdown,
    plan: source.plan,
    input: {
      topic: source.topic,
      audience: source.audience,
      tone: source.tone,
      wordCount: source.wordCount,
      cta: source.cta,
      goal: source.goal,
      proofPoints: source.proofPoints,
      systemExample: source.systemExample
    }
  }
}];
